var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"나는 아직 잘 모르겠어. 모건 할배.","JPN":"俺はまだよくわからない。モーガンのジジイ。","ENG":"Morgan, I still have no idea.","TWN":"我還不太明白，摩根老頭。"},"stage":{"bg":"BLACK","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_BD_C_ROI_PR_IN_TRAILER_1"},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"훗, 흥미롭군.","JPN":"なかなか興味深いな。","ENG":"Hah. Intriguing.","TWN":"呵，真有意思。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"제길, 또 끊어져 버렸어!","JPN":"くそ、また切れちまった！","ENG":"Dammit, it broke again!","TWN":"該死，又斷了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_METAL"},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"할배가 물려줬던 사슬은 이 정도로 약하지 않았는데!","JPN":"ジジイにもらった鎖はこんなに弱くなかったのに！","ENG":"The chain that my grandfather left me wasn't this weak!","TWN":"爺爺傳給我的鐵鍊，我記得沒這麼脆弱啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"투덜거릴 여유 따위는 없어요, 물벼룩!","JPN":"愚痴ってる暇はありません、ミジンコ！","ENG":"There is no time to complain, Water Flea!","TWN":"你現在沒有時間發牢騷了，水蚤。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"우리 할아버지가 어떤 선택을 하려고 했는지.","JPN":"お爺さんがどんな選択をしようとしたのか。","ENG":"What would've my grandfather done?","TWN":"我爺爺會做出什麼選擇。"},"stage":{"bg":"BLACK","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_BD_C_ROI_PR_IN_TRAILER_2"},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 나에게 정말로 프리드웬을 이어받을 자격이 있는지.","JPN":"それに俺が本当にプリドウェンを受け継ぐ資格があるのか。","ENG":"And am I really fit to succeed Prydwen?","TWN":"而我又是否真的有資格繼承普利多溫。"},"stage":{"bg":"BLACK","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_BD_C_ROI_PR_IN_TRAILER_3"},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 당장 버넷 경만큼, 견고한 사슬을 만들어 내지 못하면.","JPN":"今すぐバーネット卿のものほど丈夫な鎖を生み出せないと。","ENG":"If you can't make chains as sturdy as Sir Burnett used to.","TWN":"如果你現在不能做出像伯內特卿的那般堅固的鐵鍊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"우리에게 승산은 없습니다.","JPN":"私たちに勝ち目はありません。","ENG":"There is no chance of us winning.","TWN":"那我們根本沒有勝算。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"제길, 알고 있다고!","JPN":"くそ、わかってるよ！","ENG":"Crap, I know!","TWN":"可惡，我知道！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_32"},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"나는 여전히…… 잘 모르겠어.","JPN":"俺はいまだに……よくわからない。","ENG":"I'm still... not sure.","TWN":"我還是……不太明白。"},"stage":{"bg":"BLACK","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_BD_C_ROI_PR_IN_TRAILER_4"},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"아직 무르지만, 제법 날카롭군.","JPN":"まだ未熟だが、なかなか鋭い。","ENG":"It's still weak, but quite sharp at the same time.","TWN":"雖然還很脆弱，但還蠻鋒利的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"사슬의 형태가 네놈에게 걸맞게 변화한 걸 보면.","JPN":"鎖の形が貴様に合わせて変化しているのを見ると。","ENG":"Seeing as how the form of the chain changes to fit you,","TWN":"鐵鍊的形體變得非常適合你。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"그 까다로운 방패가 네놈을 어느정도 주인으로 인정한 모양이야.","JPN":"あの気難しい盾が、貴様を主として少しは認めたようだ。","ENG":"perhaps that picky shield acknowledged you as its owner.","TWN":"看來那個挑剔的盾牌，在某種程度上認可了你。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"뭐라고?","JPN":"何だって？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"하지만 아직 집념이 부족해!","JPN":"だが、まだ執念が足りない！","ENG":"But you're not desperate enough!","TWN":"但執念還不夠！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"크하아아악……!!","JPN":"ぐあああああっ！！","ENG":"Graah!!","TWN":"呃啊啊啊……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"로이 버넷……!!","JPN":"ロイ・バーネット……！！","ENG":"Roy Burnett...!!","TWN":"羅伊·伯內特……！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"},"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"저희가 시간을 벌어드리겠습니다!","JPN":"私たちが時間を稼ぎます！","ENG":"We will buy you some time!","TWN":"我們會給你爭取時間！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"얼마 못 버틸 거야. 죽기 싫으면 빨리 일어나는 게 좋을 걸?","JPN":"長くは持たないよ。死にたくないなら、早く立ち上がった方がいいからね。","ENG":"It's not going to last long. You'd better get up quickly unless you want to die!","TWN":"我們撐不了多久啦！如果不想死，就盡快給我起來！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"전원 사격 개시!","JPN":"全員、射撃開始！","ENG":"Everyone, fire!","TWN":"全員射擊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"요원님이 회복할 수 있도록 1초라도 더 버는 거다!","JPN":"エージェントが回復できるように、1秒でも稼ぐんだ！","ENG":"Buy the agent more time to recover!","TWN":"多撐一秒也好，直到特工恢復！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"쳇, 성가신 놈들.","JPN":"ちっ、目障りな奴らだ。","ENG":"Tsk. Pests.","TWN":"嘖，麻煩的傢伙。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"전부 말살해주지……!","JPN":"全員抹殺してやる……！","ENG":"I'll exterminate you all...!","TWN":"就讓我殺了你們全部……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"……홍차 폭탄?","JPN":"……紅茶爆弾？","ENG":"...Tea Bomb?","TWN":"……紅茶炸彈？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"크흑, 일어나야 해……!","JPN":"くうっ、立ち上がらねえと……！","ENG":"Kgh, I have to get up...!","TWN":"咳，必須……起來……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"출혈이 심합니다. 움직일 수 있겠어요?","JPN":"出血がひどいです。動けますか？","ENG":"You're bleeding profusely. Can you move?","TWN":"你出血很嚴重，能動嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"……가자.","JPN":"……行くぞ。","ENG":"...Let's go.","TWN":"……走吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"모두가 시간을 벌어주고 있어.","JPN":"皆が時間を稼いでくれてる。","ENG":"Everyone's buying us time.","TWN":"大家都在給我爭取時間。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"우리가 늦으면, 또 누군가 죽거나 다칠 거야.","JPN":"俺たちが遅れれば、また誰かが死ぬか傷つく。","ENG":"If we're late, someone else is going to get hurt or die.","TWN":"如果我們錯過，又會有人死亡或者受傷。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"난 이제 그런 꼴, 더는 보고 싶지 않아.","JPN":"俺はもう二度とあんな光景は見たくない。","ENG":"And I don't want to see that anymore.","TWN":"我再也不想看到那個樣子了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"너도 알고 있잖아, 엘리자베스.","JPN":"お前もわかってるだろ、エリザベス。","ENG":"You know it too, Elizabeth.","TWN":"伊莉莎白，你也知道的。"},"stage":{"bg":"PRYDWEN_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"이 싸움에서 우리는 절대 꺾여서는 안 된다는 걸.","JPN":"俺たちはこの戦いで決して屈してはならないって。","ENG":"We cannot be defeated in this fight.","TWN":"在這場戰鬥中，我們絕對不能屈服。"},"stage":{"bg":"PRYDWEN_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"……훗.","JPN":"……ふっ。","ENG":"...Hmph.","TWN":"……呵。"},"stage":{"bg":"PRYDWEN_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"은근슬쩍 친한 척하지 말아 줄래요, 물벼룩?","JPN":"さりげなく馴れ馴れしい呼び方をしないでくれますか？　ミジンコ。","ENG":"Don't act so chummy with me, Water Flea.","TWN":"不要裝作很親近的樣子，水蚤。"},"stage":{"bg":"PRYDWEN_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"시끄럽다고, 홍차 폭탄.","JPN":"うるせえ、紅茶爆弾。","ENG":"Shut up, Tea Bomb.","TWN":"吵死了，紅茶炸彈。"},"stage":{"bg":"PRYDWEN_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 내가 택했던 선택이 잘못된 것이라고 생각하지는 않아.","JPN":"だけど、俺の選択が間違ってるとは思わない。","ENG":"But I don't think my choices were wrong.","TWN":"不過我不認為我的選擇是錯誤的。"},"stage":{"bg":"PRYDWEN_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_BD_C_ROI_PR_IN_TRAILER_5"},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 그 선택에 대한 책임을 지기 위해서라면.","JPN":"それに、その選択に対しての責任を負うためなら。","ENG":"And to take all the responsibility for my choices...","TWN":"然而，若是要為那個選擇負責，"},"stage":{"bg":"PRYDWEN_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_BD_C_ROI_PR_IN_TRAILER_6"},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"나는 기꺼이 전설을 이어받겠어.","JPN":"俺は喜んで伝説を受け継ぐ。","ENG":"I'll gladly carry on the legend.","TWN":"那我甘願繼承傳說。"},"stage":{"bg":"PRYDWEN_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_BD_C_ROI_PR_IN_TRAILER_7"},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"당신이 넘지 못했던 문턱을 내가 넘어주겠어, 새디어스 모건.","JPN":"あんたが越えられなかった扉を、俺が越えてやるよ、タデウス・モーガン。","ENG":"You were on the verge of greatness, Thaddeus Morgan. But I'll be the one to achieve it.","TWN":"你跨不過去的門檻，由我來跨越，薩迪烏斯·摩根。"},"stage":{"bg":"PRYDWEN_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_BD_C_ROI_PR_IN_TRAILER_8"},{"id":"L42_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"제법이군.","JPN":"やるな。","ENG":"I'm impressed.","TWN":"還不錯嘛。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はあ、はあ、はあ……！","ENG":"*Huff*... *Huff*... *Huff*...!","TWN":"哈啊，哈啊，哈啊……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"제길……!!","JPN":"くそ……！！","ENG":"Bollocks...!!","TWN":"可惡……！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"방패를 든 건 처음일 텐데…….","JPN":"盾を手にしたのは初めてのはずだが……","ENG":"This should be the first time he's wielding the shield...","TWN":"明明是第一次拿起盾牌……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"처음과는 비교도 할 수 없을 정도로 사슬이 견고해졌어.","JPN":"最初とは比べ物にならないほど、堅固な鎖になっている。","ENG":"but the chain is much sturdier than in the beginning.","TWN":"鐵鍊卻變得異常堅固，最開始的鐵鍊根本無法與之相比。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"아직은 멀었지만.","JPN":"まだまだだがな。","ENG":"He's still no match, however.","TWN":"不過，還差得遠。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"크윽!","JPN":"くうっ！","ENG":"Urgh!","TWN":"咳！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"대체…… 너는 정체가 뭐야?","JPN":"お前はいったい……何者だ？","ENG":"What... are you?","TWN":"你到底……是什麼人？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"어떻게 프리드웬을 알고 있는 거지?","JPN":"なぜプリドウェンを知っている？","ENG":"How do you know Prydwen?","TWN":"你怎麼會知道普利多溫？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"어리석은 질문이로군.","JPN":"愚問だな。","ENG":"A foolish question.","TWN":"真是個愚蠢的問題。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"알고 있을 수밖에 없지. 그 방패는 원래 내 것이었으니까.","JPN":"知っていて当然だろう。その盾は本来俺のものだったからな。","ENG":"Of course I know. That shield was originally mine.","TWN":"我當然知道，因為那盾牌本來就是我的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"뭐라고……?","JPN":"何だと……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"제 기관원에게 손 떼세요! 호수의 기사!","JPN":"私の機関員から手を離しなさい、湖の騎士！","ENG":"Take your hands off of my agent, Knight of the Lake!","TWN":"放開我的機關成員！湖水騎士！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"호오……?","JPN":"ほう……？","ENG":"Ho-oh...?","TWN":"喔……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"홍차 폭탄? 너, 그 모습은……?","JPN":"紅茶爆弾？　お前……その姿は？","ENG":"Tea Bomb? Your appearance...","TWN":"紅茶炸彈？你，你的樣子……？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"날개라……. 이 세계의 팬드래건은 벌써 그런 걸 쓸 수 있나?","JPN":"翼か……この世界のペンドラゴンは、すでにそんな技が使えるのか。","ENG":"Wings... Is Pendragon of this world already able to use that?","TWN":"翅膀啊……這個世界的潘德拉貢已經可以使用那個力量了嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"재미있군. 분명 대가를 지불하게 될 텐데?","JPN":"面白い。きっと対価を払うことになるぞ。","ENG":"Interesting. It will surely take a toll on you.","TWN":"有意思，但肯定要付出代價的？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","text":{"KOREA":"헛소리는 집어치우세요!","JPN":"戯言はよしなさい！","ENG":"Enough with your nonsense!","TWN":"別說廢話了！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_HATE"},"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","text":{"KOREA":"여기서 이 모습을 보인 이상, 당신들을 그냥 보내줄 생각은 없습니다.","JPN":"ここでこの姿を見られた以上、あなたたちを逃がすつもりはありません。","ENG":"Since you've witnessed this form, I have no intentions of letting you go.","TWN":"既然在這裡讓你們看到了這個樣子，我就沒打算要放你們走。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"으음~ 의견이 일치하네요. 기관장님?","JPN":"うーん、それは同意見ですね。機関長。","ENG":"Hmm. I guess we are of the same opinion then, Chief.","TWN":"嗯♬～我們的意見一致呢，機關長？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ONLY_CA_SHADOW_PASSIVE_2"},{"id":"L29_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"저도 여기있는 분들을 그냥 돌려 보내드릴 생각이 없었는 걸요?","JPN":"私もここにいる皆さんを帰すつもりなんてないんですよ？","ENG":"I had no intentions of letting these people go, either.","TWN":"我也沒打算就這麼放走這裡的人呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"특히…….","JPN":"特に……","ENG":"Especially if...","TWN":"尤其是……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"입맛만 다셔보고, 그만 놓쳐버린 성찬이 있어서요.","JPN":"舌なめずりだけして、逃がしてしまった聖餐がありましてね。","ENG":"there's a feast I was only able to smell but not have a bite of.","TWN":"之前錯過了一次盛宴，讓我耿耿於懷。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"한 차례 시련을 이겨내고, 스스로의 의지로 다시 이 자리에 선 당신은…….","JPN":"試練を乗り越え、自らの意思で再びここに来たあなたは……","ENG":"You've overcome hardship and are standing again with your own will...","TWN":"在經受了一次考驗後，以自己的意志重新站在這裡的你……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"가슴 속에 얼마나 감미롭고, 달콤한 정보를 간직하고 있을까요?","JPN":"胸の中にどれほど甘美で魅力的な情報を秘めているでしょう？","ENG":"What kind of rich, sweet flavor of information do you hold within?","TWN":"內心會有多麼甜美，多麼甜蜜的資訊呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"……로이 버넷?","JPN":"……ロイ・バーネット？","ENG":"...Roy Burnett?","TWN":"……羅伊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"어디 먹을 수 있으면, 또 먹어 봐. 배탈 나게 해줄 테니까.","JPN":"食えるもんなら食ってみろ。腹を下させてやるからな。","ENG":"You're welcome to try eating me. I'll cause a helluva stomach ache if you do.","TWN":"那你就來試試看吧，我肯定會讓你拉肚子。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"아하하하하핫! 재밌으셔라!","JPN":"あはははははっ！　冗談が上手いですね！","ENG":"Ahahaha! How funny!","TWN":"哈哈哈哈哈！有意思！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"여기까지 하시지요, 어머니.","JPN":"ここまでにしましょう、お母さん。","ENG":"We should stop, Mother.","TWN":"到此為止吧，母親。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"에엥? 어째서예요? 기사님?","JPN":"ええっ？　どうしてですか、騎士様？","ENG":"Ehh? But why?","TWN":"嗯？為什麼？騎士？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"우웅! 하필 저렇게 맛있어 보이는 성찬을 앞에 두고!","JPN":"うーん！　あんなにおいしそうな聖餐が目の前にいるのに！","ENG":"Mmph! There's a yummy looking feast right in front of us!","TWN":"哎呀！明明那麼美味的盛宴就在眼前！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"지진……?","JPN":"地震……？","ENG":"An earthquake...?","TWN":"地震……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"어머니를 담은 그릇은 아주 오랫동안 이 세계에 뿌리를 내리며 핵의 역할을 해왔습니다.","JPN":"お母さんを宿している器は、長い間この世界に根を張り核として機能していました。","ENG":"For a long time, the vessel that you inhabit has been laying down roots in this world and acting as its core.","TWN":"裝著母親的器皿在這個世界上紮根了很長時間，起到了核心的作用。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그리고 그 핵이 소멸한 지금.","JPN":"その核が消滅した今……","ENG":"And now that the core is gone.","TWN":"而那個核心消失的現在……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"이 세계는 곧 그 수명을 다해, 완전히 수축하여 소멸하게 되겠죠.","JPN":"この世界は寿命が尽き、完全に収縮して消滅するでしょう。","ENG":"This world is coming to an end, shrinking and disappearing.","TWN":"這個世界即將壽終正寢，徹底收縮消亡。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그 전에 여길 뜨는 것이 좋을 겁니다.","JPN":"そうなる前に、ここから離れたほうが安全です。","ENG":"It is best that you leave before that happens.","TWN":"所以，最好在那之前離開這裡。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"으음~ 기사님께서 그렇게 말씀하신다면 뭐, 어쩔 수 없네요.","JPN":"うーん、騎士様がそうおっしゃるなら、仕方ないですね。","ENG":"Hmm... If you say so, my knight.","TWN":"嗯～既然騎士都這麼說了，那就沒辦法了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"어떠세요, 기관장님? 오늘은 무승부로 하지 않을래요?","JPN":"どうですか、機関長？　今日のところは引き分けにしません？","ENG":"What do you think, Chief? Shall we consider this a draw?","TWN":"怎麼樣，機關長？今天就算平手了吧？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"저희가 특별히 양보해서, 다음 성찬은 당분간 미루어 드릴게요.","JPN":"特別に今日は大目にみて、聖餐を次回に延期してあげます。","ENG":"We will be nice and postpone the next feast.","TWN":"我們特意讓你一步，下一次盛宴暫且推遲吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"어차피 저희도 조금 준비가 필요하기도 하고.","JPN":"私たちにもちょっと準備が必要ですしね。","ENG":"After all, we are in need of some preparation too.","TWN":"正好，我們也需要準備一下。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"무승부라고?","JPN":"引き分けだと？","ENG":"A draw?","TWN":"平手？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"장난해? 이 꼴을 보고 넘어가자는 거야?","JPN":"冗談もほどほどにしろ。ここまできて解散ってことか？","ENG":"Are you kidding me? You want to just leave after everything?","TWN":"你在開玩笑嗎？都到這地步了，難道就要這麼放棄？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"개소리 집어치워!","JPN":"ふざけんな！","ENG":"Cut the crap!","TWN":"別和她說廢話啊！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BALL"},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"끄윽! 하아, 하아……!","JPN":"くうっ！　はあ、はあ……！","ENG":"Kgh! *Huff... Huff...*","TWN":"呃啊！哈啊，哈啊……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아야, 아야야……!","JPN":"いたっ、いたた……！","ENG":"Oww, ouch...!","TWN":"啊呀，啊呀呀……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"돌아가죠.","JPN":"戻りましょう。","ENG":"We shall return.","TWN":"回去吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"야, 홍차 폭탄……!!","JPN":"おい、紅茶爆弾……！！","ENG":"Hey, Tea Bomb...!!","TWN":"喂，紅茶炸彈……！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"},"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"오늘, 기관은 너무나 많은 것들을 잃었습니다.","JPN":"今日、機関はあまりにも多くのものを失いました。","ENG":"The Institution has lost too much today.","TWN":"今天，機關失去了太多東西。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이 이상 누군가를 잃게 된다면, 저는 스스로를 용서할 수 없을 것 같군요.","JPN":"これ以上誰かを失ってしまったら、私は自分を許せなくなる気がします。","ENG":"I will not be able to forgive myself if we lose anyone else today.","TWN":"如果再失去某些人，我想我不能原諒我自己。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"살아만 있다면 뒷일은 다 같이 머리를 맞대고 고민하면 됩니다.","JPN":"生きてさえいれば、後のことはみんなで考えればいいものです。","ENG":"As long as we're alive, we can all put our heads together and think of a way to sort out the rest.","TWN":"只要活著，以後的事情大家一起思考就可以了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니 지금은 돌아가죠.","JPN":"ですから、今は戻りましょう。","ENG":"So let us return for now.","TWN":"所以，現在還是回去吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관장으로서의 명령입니다.","JPN":"機関長の命令です。","ENG":"This is an order from your Chief.","TWN":"這是作為機關長的命令。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"젠장, 알겠다고.","JPN":"ちくしょう……わかったよ。","ENG":"Bollocks, fine.","TWN":"該死，我知道了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"후후, 역시 팬드래건 기관장님께서는 똑똑하시네요.","JPN":"ふふ、やはりペンドラゴン機関長は賢い方ですね。","ENG":"Fu fuu, Chief Pendragon certainly is smart.","TWN":"呵呵，果然潘德拉貢機關長很聰明。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"나중에 하나가 되면, 오늘 기분을 꼭 여쭈어 보고 싶어요.","JPN":"いつか一つになったら、今日の気持ちをじっくり聞いてみたいです。","ENG":"I want to ask how you felt today once we become one in the future.","TWN":"如果以後合而為一，那我很想問一下今天的心情。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"바이바이~ 그럼, 다들 다음 성찬식에서 봬요.","JPN":"バイバイ―じゃあ、次回の聖餐式で会いましょう。","ENG":"Bye-bye! See you all at the next feast.","TWN":"再見了～那麼，在下次的盛宴儀式上再見吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};